mapper.select:
select '90-100' as rangename, count(*) as num
from scoreinfo sc
left join classinfo cl on sc.scClassId = cl.cId
left join majorinfo mj on cl.cMajorId = mj.mId
left join courseinfo cr on sc.scCourseId = cr.crId

    sc.scScore >= 90


            and sc.scTermId = #{dto.yid}


            and sc.scClassId = #{dto.cid}


            and sc.scCourseId = #{dto.crid}


            and cl.cMajorId = #{dto.majorid}


            and mj.mCollegeId = #{dto.collegeid}


            and (
            cr.crName like concat('%', #{dto.qkey}, '%')
            or cl.cName like concat('%', #{dto.qkey}, '%')
            )




union all

select '80-89' as rangename, count(*) as num
from scoreinfo sc
left join classinfo cl on sc.scClassId = cl.cId
left join majorinfo mj on cl.cMajorId = mj.mId
left join courseinfo cr on sc.scCourseId = cr.crId

    sc.scScore >= 80 and sc.scScore < 90


            and sc.scTermId = #{dto.yid}


            and sc.scClassId = #{dto.cid}


            and sc.scCourseId = #{dto.crid}


            and cl.cMajorId = #{dto.majorid}


            and mj.mCollegeId = #{dto.collegeid}


            and (
            cr.crName like concat('%', #{dto.qkey}, '%')
            or cl.cName like concat('%', #{dto.qkey}, '%')
            )




union all

select '70-79' as rangename, count(*) as num
from scoreinfo sc
left join classinfo cl on sc.scClassId = cl.cId
left join majorinfo mj on cl.cMajorId = mj.mId
left join courseinfo cr on sc.scCourseId = cr.crId

    sc.scScore >= 70 and sc.scScore < 80


            and sc.scTermId = #{dto.yid}


            and sc.scClassId = #{dto.cid}


            and sc.scCourseId = #{dto.crid}


            and cl.cMajorId = #{dto.majorid}


            and mj.mCollegeId = #{dto.collegeid}


            and (
            cr.crName like concat('%', #{dto.qkey}, '%')
            or cl.cName like concat('%', #{dto.qkey}, '%')
            )




union all

select '60-69' as rangename, count(*) as num
from scoreinfo sc
left join classinfo cl on sc.scClassId = cl.cId
left join majorinfo mj on cl.cMajorId = mj.mId
left join courseinfo cr on sc.scCourseId = cr.crId

    sc.scScore >= 60 and sc.scScore < 70


            and sc.scTermId = #{dto.yid}


            and sc.scClassId = #{dto.cid}


            and sc.scCourseId = #{dto.crid}


            and cl.cMajorId = #{dto.majorid}


            and mj.mCollegeId = #{dto.collegeid}


            and (
            cr.crName like concat('%', #{dto.qkey}, '%')
            or cl.cName like concat('%', #{dto.qkey}, '%')
            )




union all

select '0-59' as rangename, count(*) as num
from scoreinfo sc
left join classinfo cl on sc.scClassId = cl.cId
left join majorinfo mj on cl.cMajorId = mj.mId
left join courseinfo cr on sc.scCourseId = cr.crId

    sc.scScore < 60


            and sc.scTermId = #{dto.yid}


            and sc.scClassId = #{dto.cid}


            and sc.scCourseId = #{dto.crid}


            and cl.cMajorId = #{dto.majorid}


            and mj.mCollegeId = #{dto.collegeid}


            and (
            cr.crName like concat('%', #{dto.qkey}, '%')
            or cl.cName like concat('%', #{dto.qkey}, '%')
            )

select yt.yId as yid, yt.yAll as termname, round(avg(sc.scScore), 2) as avgscore, round(sum(case when sc.scScore >= 60 then 1 else 0 end) * 100.0 / count(*), 2) as passrate, round(sum(case when sc.scScore >= 90 then 1 else 0 end) * 100.0 / count(*), 2) as excellentrate from scoreinfo sc left join yearterm yt on sc.scTermId = yt.yId left join classinfo cl on sc.scClassId = cl.cId left join majorinfo mj on cl.cMajorId = mj.mId left join courseinfo cr on sc.scCourseId = cr.crId
and sc.scTermId = #{dto.yid}
and sc.scClassId = #{dto.cid}
and sc.scCourseId = #{dto.crid}
and cl.cMajorId = #{dto.majorid}
and mj.mCollegeId = #{dto.collegeid}
and ( cr.crName like concat('%', #{dto.qkey}, '%') or cl.cName like concat('%', #{dto.qkey}, '%') )
group by yt.yId, yt.yAll order by yt.yId asc
